import React from 'react';
import './world-map.css'; // Import your CSS styles
import mapsData from './maps.json'; // Import the map data

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      selectedCountyIndex: 0, // Index of the currently selected county
      playerPosition: {
        row: 0,
        col: 0,
      },
      message: '',
    };
  }

  componentDidMount() {
    this.updateMessage();
    window.addEventListener('resize', this.handleResize);
  }

  componentWillUnmount() {
    window.removeEventListener('resize', this.handleResize);
  }

  updateMessage = () => {
    const message = window.innerWidth > window.innerHeight ? 'Landscape' : 'Portrait';
    this.setState({ message });
  };

  handleResize = () => {
    this.updateMessage();
  };

  canMove = (row, col) => {
    const { mapData } = this.getCurrentCounty();
    return mapData[row][col] !== 9;
  };

  handleTileTouch = (row, col) => {
    const { mapData } = this.getCurrentCounty();

    if (this.canMove(row, col)) {
      this.setState({
        playerPosition: { row, col },
      });

      if (mapData[row][col] === 2) {
        alert('You are at a map location!');
      }
    }
  };

  getCurrentCounty = () => {
    const { selectedCountyIndex } = this.state;
    return mapsData[selectedCountyIndex];
  };
  renderGameBoard() {
    const { playerPosition } = this.state;
    const { mapData } = this.props;

    return mapData.map((row, rowIndex) => (
      <div key={`row-${rowIndex}`} className="game-row">
        {row.map((tile, colIndex) => {
          const isPlayerTile = rowIndex === playerPosition.row && colIndex === playerPosition.col;
          const isHighlighted =
            Math.abs(rowIndex - playerPosition.row) <= 2 &&
            Math.abs(colIndex - playerPosition.col) <= 2;

          return (
            <div
              key={`tile-${rowIndex}-${colIndex}`}
              className={`game-tile ${
                tile === 9 ? 'non-walkable' : ''
              } ${isPlayerTile ? 'player-icon' : ''} ${
                isHighlighted ? 'highlighted' : ''
              }`}
              onTouchStart={() => this.handleTileTouch(rowIndex, colIndex)}
            >
              {tile === 0 && <div className="obstacle"></div>}
            </div>
          );
        })}
      </div>
    ));
  }

  render() {
    const { message } = this.state;
    const currentCounty = this.getCurrentCounty();

    return (
      <div className="world-map-container">
        <h1>{message}</h1>
        <h2>{currentCounty.co}</h2>
        <div className="world-map">{this.renderGameBoard()}</div>
      </div>
    );
  }
}

export default Overworld;
